    in_degree = {node: 0 for node in graph}

    # Calculate the in-degree of each node
    for nodes in graph.values():
        for node in nodes:
            in_degree[node] += 1

    # Initialize a queue with all nodes that have no incoming edges
    from collections import deque
    queue = deque([node for node, degree in in_degree.items() if degree == 0])

    top_order = []

    # Process until the queue is empty
    while queue:
        node = queue.popleft()
        top_order.append(node)

        # Decrease in-degree of each neighbor by one and add to queue if no incoming edges
        for dependent_node in graph[node]:
            in_degree[dependent_node] -= 1
            if in_degree[dependent_node] == 0:
                queue.append(dependent_node)

    # If the length of top_order is not equal to the number of nodes, it means there was a cycle and no valid topological sort exists.
    if len(top_order) != len(in_degree):
        raise ValueError("The graph contains a cycle, so a topological ordering does not exist.")

    return top_order
